const rawOutput = $input.first().json.output;

let brief;
try {
  // Strip markdown code fences if present
  const cleaned = rawOutput.replace(/```json\n?|```/g, '').trim();
  brief = JSON.parse(cleaned);
} catch (e) {
  return [{ json: { error: 'Failed to parse AI output', raw: rawOutput } }];
}

return [
  {
    json: {
      success: true,
      generated_at: new Date().toISOString(),
      brief
    }
  }
];
